sys_script_include.script:
function GetInstanceAIStatus()
{
	aistatus = {};

	// Now Assist Agents is installed
	aistatus.now_assist_agents_installation = {};
	aistatus.now_assist_agents_installation.status = IsNowAssistAIAgentsInstalled();
	aistatus.now_assist_agents_installation.info = 'Is true if required plugins are installed to use AI Agents.';

	// Now Assist Panel is active
	aistatus.now_assist_panel = {};
	aistatus.now_assist_panel.status = false;
	aistatus.now_assist_panel.info = 'True if the Now Assist Panel is "turned on" on the page '+GetInstanceUrl() +'now/now-assist-admin/now-assist-panel.';

	var grNAS = new GlideRecord('sn_nowassist_settings');
	grNAS.addQuery('type','=','nap');
	grNAS.addQuery('name','=','Now Assist Panel Settings');
	grNAS.addQuery('active','=',true);
	grNAS.query();
	while (grNAS.next())
	{
		var variables = GetVariablesFromRecord(grNAS);
		if (GetValue(variables,'nap_enabled','value') == 1)
		{
			aistatus.now_assist_panel.status = true;
		}
		Debug(variables);
	}

	// Now Assist Panel - Platform (default)

	var grNAPDC = new GlideRecord('sys_now_assist_deployment_channel');
	grNAPDC.addQuery();

	/*
	<active>false</active>
<advanced_script/>
<config_type/>
<document_id>c86a62e2c7022010099a308dc7c26022</document_id>
<document_table>sys_ux_app</document_table>
<experience>self_service_dialog</experience>
<full_page_search/>
<now_assist_deployment display_value="Now Assist Panel - Platform (default)">7bd9820f14475650f87711349c1171be</now_assist_deployment>
<search_application/>
<sys_class_name>sys_now_assist_deployment_channel</sys_class_name>
<sys_created_by>admin</sys_created_by>
<sys_created_on>2026-05-21 10:19:16</sys_created_on>
<sys_domain>global</sys_domain>
<sys_id>241bcf20eb8d4790b13dfd72bad0cdcc</sys_id>
<sys_mod_count>1</sys_mod_count>
<sys_name>c86a62e2c7022010099a308dc7c26022</sys_name>
<sys_package display_value="Global" source="global">global</sys_package>
<sys_policy/>
<sys_scope display_value="Global">global</sys_scope>
<sys_update_name>sys_now_assist_deployment_channel_241bcf20eb8d4790b13dfd72bad0cdcc</sys_update_name>
<sys_updated_by>admin</sys_updated_by>
<sys_updated_on>2026-05-21 14:52:21</sys_updated_on>
	 */

	aistatus.now_assist_panel_platform = {};
	aistatus.now_assist_panel_platform.status = false;
	aistatus.now_assist_panel_platform.info = 'TODO';

	// sn_nowassist_admin.ignoreFulfillerSubscriptionCheck
	aistatus.now_assist_ignore_fulfiller_subscription_check = {};
	aistatus.now_assist_ignore_fulfiller_subscription_check.status = 
		GetBoolValue(
			GetProperty('sn_nowassist_admin.ignoreFulfillerSubscriptionCheck'));
	aistatus.now_assist_ignore_fulfiller_subscription_check.info = 
		'True if the system property sn_nowassist_admin.ignoreFulfillerSubscriptionCheck is set to "true". Setting this system property is documented as a fix to PRB1965167.';

	return aistatus;
}
